mapper.select:
SELECT sa.*
FROM schedule_attendance sa
WHERE sa.schedule_id = #{scheduleId}
  AND sa.user_key    = #{userKey}
  AND sa.is_latest   = 1
LIMIT 1

mapper.update:
UPDATE schedule_attendance
SET is_latest = 0
WHERE schedule_id = #{scheduleId}
  AND user_key    = #{userKey}
  AND is_latest   = 1
